bomData.valueScript:
// Filter function to get all the hardware elements for the leg
let HardwareElements = GlobalFunc.find_HardwareLibraryMapping(part.pa_HardwareId);

// Cycle to add all hardware elements to the BOM
HardwareElements.forEach(info => {
  let elem = this.addbomout_Hardware();
  let LegBOMInfo = GlobalFunc.find_HardwareLibrary(info.SupplierArticleNumber!,info.Supplier!);
  let LegBOMName = GlobalFunc.find_PartSettings("part_Leg");

  elem.bom_Supplier=info.Supplier;
  elem.bom_SupplierArticle=info.SupplierArticleNumber;
  elem.bom_Description1=LegBOMInfo.Description;
  elem.bom_Description2=LegBOMInfo.Description2;
  elem.bom_Length=LegBOMInfo.Length;
  elem.bom_Width=LegBOMInfo.Width;
  elem.bom_Thk=LegBOMInfo.Thickness;
  elem.bom_Color=LegBOMInfo.Color;
  elem.bom_Weight=LegBOMInfo.Weight;
  elem.bom_Name=LegBOMName.BomPartDescription;
  elem.bom_Type=part._partId;
  elem.bom_PartId=part._id;
  elem.bom_ParentId=parentId;
  elem.bom_Qty=info.BomQty;
})
